# Text Adventure — Step 9: Combat System with Inheritance
# Design a combat system using base and derived classes.

class Item:
    def __init__(self, name, item_type, value):
        self.name = name
        self.item_type = item_type
        self.value = value

    def __str__(self):
        return f"{self.name} ({self.item_type})"


class Room:
    def __init__(self, name, description):
        self.name = name
        self.description = description
        self.items = []

    def __str__(self):
        return f"{self.name}: {self.description}"

    def add_item(self, item):
        self.items.append(item)

    def remove_item(self, item_name):
        for i, item in enumerate(self.items):
            if item.name == item_name:
                return self.items.pop(i)
        return None


class Character:
    """Base class for all characters (player and enemies)."""
    def __init__(self, name, health, attack_power, defense):
        # Store all attributes; set max_health = health
        pass

    def is_alive(self):
        """Return True if health > 0."""
        pass

    def attack(self, target):
        """Attack a target Character. Deal max(0, self.attack_power - target.defense) damage.
        Return the damage dealt."""
        pass

    def take_damage(self, amount):
        """Reduce health by amount (minimum health is 0). Return actual damage taken."""
        pass

    def __str__(self):
        return f"{self.name} (HP: {self.health}/{self.max_health})"


class Player(Character):
    """The player character with an inventory."""
    def __init__(self, name, health=100, attack_power=15, defense=5):
        super().__init__(name, health, attack_power, defense)
        self.inventory = []

    def pick_up(self, item):
        self.inventory.append(item)


class Enemy(Character):
    """An enemy that drops loot when defeated."""
    def __init__(self, name, health, attack_power, defense, loot=None):
        # Call super().__init__ and store loot attribute
        pass

    def get_loot(self):
        """Return the loot item if the enemy is defeated, else None."""
        if not self.is_alive() and self.loot is not None:
            return self.loot
        return None


# Build a combat encounter
hero = Player('Hero', health=100, attack_power=18, defense=5)
goblin_loot = Item('goblin_dagger', 'weapon', 8)
goblin = Enemy('Goblin', health=40, attack_power=10, defense=3, loot=goblin_loot)

print(f"{hero} vs {goblin}")
round_num = 1
while hero.is_alive() and goblin.is_alive():
    dmg_to_goblin = hero.attack(goblin)
    print(f"Round {round_num}: Hero deals {dmg_to_goblin} damage -> {goblin}")
    if goblin.is_alive():
        dmg_to_hero = goblin.attack(hero)
        print(f"           Goblin deals {dmg_to_hero} damage -> {hero}")
    round_num += 1

if hero.is_alive():
    loot = goblin.get_loot()
    if loot:
        hero.pick_up(loot)
        print(f"Hero picked up {loot}!")
    print("Victory!")
else:
    print("Defeat...")
